def trap(height):
    lo, hi = 0, len(height)-1
    max_l = max_r = water = 0
    while lo <= hi:
        if height[lo] <= height[hi]:
            max_l = max(max_l, height[lo])
            water += max_l - height[lo]; lo += 1
        else:
            max_r = max(max_r, height[hi])
            water += max_r - height[hi]; hi -= 1
    return water

